# checkers_game/checkers/Board.py

class Board:
    def __init__(self):
        self.board = self.initialize_board()
        self.kings = {'white': [], 'black': []}

    def initialize_board(self):
        board = [[''] * 8 for _ in range(8)]
        for row in range(3):
            for col in range(row % 2, 8, 2):
                if row == 1:
                    board[row][col] = 'B'
                elif row == 6:
                    board[row][col] = 'W'
                else:
                    board[row][col] = '.'
        return board

    def print_board(self):
        for row in self.board:
            print(' | '.join(row))
            print('-' * 15)

    def is_valid_move(self, start_pos, end_pos, player):
        start_row, start_col = ord(start_pos[0]) - ord('a'), int(start_pos[1]) - 1
        end_row, end_col = ord(end_pos[0]) - ord('a'), int(end_pos[1]) - 1

        if self.board[start_row][start_col] != player:
            return False

        if (end_row, end_col) not in self.get_possible_moves(start_row, start_col, player):
            return False

        return True

    def get_possible_moves(self, row, col, player):
        moves = []
        directions = [(-1, -1), (-1, 1)] if player == 'white' else [(1, -1), (1, 1)]
        for dr, dc in directions:
            new_row, new_col = row + dr, col + dc
            if self.is_within_bounds(new_row, new_col) and self.board[new_row][new_col] == '.':
                moves.append((new_row, new_col))
                capture_row, capture_col = new_row + dr, new_col + dc
                while self.is_within_bounds(capture_row, capture_col):
                    if self.board[capture_row][capture_col] in ('W', 'B'):
                        moves.append((capture_row, capture_col))
                        capture_row += dr
                        capture_col += dc
                    else:
                        break

        return moves

    def apply_move(self, start_pos, end_pos):
        start_row, start_col = ord(start_pos[0]) - ord('a'), int(start_pos[1]) - 1
        end_row, end_col = ord(end_pos[0]) - ord('a'), int(end_pos[1]) - 1

        if (end_row, end_col) in self.get_possible_moves(start_row, start_col):
            piece = self.board[start_row][start_col]
            self.board[start_row][start_col] = '.'
            self.board[end_row][end_col] = piece
            if abs(end_row - start_row) == 2:
                jump_row = (end_row + start_row) // 2
                jump_col = (end_col + start_col) // 2
                self.board[jump_row][jump_col] = '.'

    def check_king(self, pos):
        row, col = ord(pos[0]) - ord('a'), int(pos[1]) - 1
        if row == 0 and self.board[row][col] == 'W' or row == 7 and self.board[row][col] == 'B':
            return True
        return False

    def has_legal_moves(self, player):
        for row in range(8):
            for col in range(8):
                if self.board[row][col] == player and len(self.get_possible_moves(row, col, player)) > 0:
                    return True
        return False

    def is_within_bounds(self, row, col):
        return 0 <= row < 8 and 0 <= col < 8
